func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	const (
		alpha = 1.0
		beta  = 0.3
		gamma = 0.7
	)
	type insertion struct {
		assignIdx int
		pos       int
		costInc   float64
		feasible  bool
	}
	unassigned := make([]int, len(oris))
	for i := range oris {
		unassigned[i] = i
	}
	for len(unassigned) > 0 {
		bestRegret := -1e9
		var bestShip int
		var bestIns insertion
		for _, idx := range unassigned {
			sid := total_ship + idx
			ori := oris[idx]
			des := dess[idx]
			var best1, best2 insertion
			best1.costInc = 1e18
			best2.costInc = 1e18
			for ai := 0; ai < dispatch.AssignsLen; ai++ {
				assignCopy := dispatch.Assigns[ai]
				if assignCopy.AddShip(sid, ori, des) {
					assignCopy.GenRoute()
					if assignCopy.Cost >= 0 {
						incr := assignCopy.Cost - dispatch.Assigns[ai].Cost
						penalty := gamma * cal_dis(assignCopy.StationCurrent, ori)
						totalIncr := incr + beta*penalty
						if totalIncr < best1.costInc {
							best2 = best1
							best1 = insertion{ai, -1, totalIncr, true}
						} else if totalIncr < best2.costInc {
							best2 = insertion{ai, -1, totalIncr, true}
						}
					}
				}
			}
			regretVal := 0.0
			selectedIns := insertion{}
			if best1.feasible && best2.feasible {
				regretVal = best2.costInc - best1.costInc
				selectedIns = best1
			} else if best1.feasible {
				regretVal = best1.costInc
				selectedIns = best1
			}
			if !best1.feasible {
				if dispatch.AssignsLen < MAXASSIGNS {
					tmpAssign := dispatch.Assigns[dispatch.AssignsLen]
					if tmpAssign.AddShip(sid, ori, des) {
						tmpAssign.GenRoute()
						if tmpAssign.Cost >= 0 {
							regretVal = 0.5 * tmpAssign.Cost
							selectedIns = insertion{dispatch.AssignsLen, -1, tmpAssign.Cost, true}
						}
					}
				}
			}
			if selectedIns.feasible && regretVal > bestRegret {
				bestRegret = regretVal
				bestShip = idx
				bestIns = selectedIns
			}
		}
		if bestRegret <= -1e8 {
			break
		}
		sid := total_ship + bestShip
